// ============ DASHBOARD CALENDAR ============
function renderDashCalendar() {
    var container = document.getElementById('dashCalendar');
    if (!container) return;

    var now = new Date();
    var year = now.getFullYear();
    var month = now.getMonth();
    var today = now.getDate();
    var firstDay = new Date(year, month, 1).getDay(); // 0=Sun
    var daysInMonth = new Date(year, month + 1, 0).getDate();
    var monthNames = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

    // Collect events for this month
    var events = {};
    // Appointments
    if (appData && appData.appointments) {
        appData.appointments.forEach(function(a) {
            if (a.date && a.date.startsWith(year + '-' + (month + 1 < 10 ? '0' : '') + (month + 1))) {
                var day = parseInt(a.date.split('-')[2]);
                if (!events[day]) events[day] = [];
                events[day].push({ type: 'appointment', label: a.type, color: '#ec4899' });
            }
        });
    }
    // Exams
    var exams = [];
    try { exams = JSON.parse(localStorage.getItem('hadassa_exams') || '[]'); } catch(e) {}
    exams.forEach(function(ex) {
        var dateStr = ex.scheduledDate || ex.date;
        if (dateStr && dateStr.startsWith(year + '-' + (month + 1 < 10 ? '0' : '') + (month + 1))) {
            var day = parseInt(dateStr.split('-')[2]);
            if (!events[day]) events[day] = [];
            events[day].push({ type: 'exam', label: ex.title, color: '#a855f7' });
        }
    });
    // DPP
    if (appData && appData.config.dpp) {
        var dppParts = appData.config.dpp.split('-');
        if (parseInt(dppParts[0]) === year && parseInt(dppParts[1]) === month + 1) {
            var dppDay = parseInt(dppParts[2]);
            if (!events[dppDay]) events[dppDay] = [];
            events[dppDay].push({ type: 'dpp', label: 'DPP - Previsão do Parto!', color: '#f59e0b' });
        }
    }

    var html = '<div style="text-align:center;margin-bottom:10px;">';
    html += '<div style="font-size:1.1em;font-weight:700;color:var(--pink-600);">' + monthNames[month] + ' ' + year + '</div>';
    html += '</div>';

    // Day headers
    html += '<div class="cal-grid">';
    ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].forEach(function(d) {
        html += '<div class="cal-header">' + d + '</div>';
    });

    // Empty cells for first week
    for (var i = 0; i < firstDay; i++) {
        html += '<div class="cal-day cal-empty"></div>';
    }

    // Days
    for (var d = 1; d <= daysInMonth; d++) {
        var isToday = d === today;
        var hasEvents = events[d] && events[d].length > 0;
        var evtDots = '';
        if (hasEvents) {
            evtDots = '<div class="cal-dots">';
            events[d].forEach(function(evt) {
                evtDots += '<span class="cal-dot" style="background:' + evt.color + ';" title="' + escapeHtml(evt.label) + '"></span>';
            });
            evtDots += '</div>';
        }

        html += '<div class="cal-day' + (isToday ? ' cal-today' : '') + (hasEvents ? ' cal-has-event' : '') + '" ' +
            (hasEvents ? 'data-cal-day="' + d + '"' : '') + '>' +
            '<span>' + d + '</span>' + evtDots + '</div>';
    }

    html += '</div>';

    // Event list for today or selected day
    html += '<div id="calEventList" style="margin-top:10px;"></div>';

    container.innerHTML = html;

    // Show today's events by default
    showCalDayEvents(today, events);

    // Click handlers
    container.querySelectorAll('[data-cal-day]').forEach(function(el) {
        el.addEventListener('click', function() {
            container.querySelectorAll('.cal-day').forEach(function(d) { d.classList.remove('cal-selected'); });
            el.classList.add('cal-selected');
            showCalDayEvents(parseInt(el.dataset.calDay), events);
        });
    });
}

function showCalDayEvents(day, events) {
    var list = document.getElementById('calEventList');
    if (!list) return;
    if (!events[day] || events[day].length === 0) {
        list.innerHTML = '';
        return;
    }
    var html = '';
    events[day].forEach(function(evt) {
        html += '<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--pink-50);font-size:0.82em;">';
        html += '<span style="width:8px;height:8px;border-radius:50%;background:' + evt.color + ';flex-shrink:0;"></span>';
        html += '<span style="color:var(--text-dark);">' + escapeHtml(evt.label) + '</span>';
        html += '</div>';
    });
    list.innerHTML = html;
}

// Override weeklyContent with full content
(function upgradeWeeklyContent() {
    // Replace the basic content with the full detailed version
    Object.keys(weeklyContentFull).forEach(function(week) {
        weeklyContent[parseInt(week)] = weeklyContentFull[parseInt(week)];
    });
})();

// Make calendar globally available
window.renderDashCalendar = renderDashCalendar;

// Render calendar now and retry until dashboard is ready
(function tryRenderCal() {
    var el = document.getElementById('dashCalendar');
    if (el && typeof appData !== 'undefined' && appData !== null) {
        renderDashCalendar();
    } else {
        setTimeout(tryRenderCal, 300);
    }
})();
